import{_ as r,o as i,c as a,ag as o,j as t,a as l}from"./chunks/framework.DXGyWiRo.js";const n="/media/202507/2025-07-09_174313_1253580.8913366555940889.png",p="/media/202507/2025-07-09_174406_2037860.8115443112985647.png",s="/media/202507/2025-07-09_174445_8852910.3590345487707123.png",_="/media/202507/2025-07-09_174547_6392470.20465110104514717.png",d="/media/202507/2025-07-09_174650_5323830.24888789469886197.png",g="/media/202507/2025-07-09_165347_1129420.913883352051953.png",c="/media/202507/2025-07-09_165430_8891040.6485372688845223.png",m="/media/202507/2025-07-09_165540_2752210.2143935295879299.png",u="/media/202508/2025-08-01_175605_8441090.451450588429793.jpeg",h="/media/202507/2025-07-09_165643_6105470.7959570790707611.png",I="/media/202507/2025-07-09_170237_4710920.23882045322953493.png",A="/media/202507/2025-07-09_170409_0509370.7668856912589257.png",z="/media/202507/2025-07-09_170648_7127140.2496154277110728.png",f="/media/202507/2025-07-09_170940_2626580.7273886523466256.png",k="/media/202507/2025-07-09_172045_4235050.4482583576880158.png",b="/media/202507/2025-07-09_172302_5943680.9390687608013244.png",C="/media/202507/2025-07-09_171209_4854990.4834578707754962.png",P="/media/202507/2025-07-09_171802_8659810.5665062312151715.png",T="/media/202507/2025-07-09_173055_0180800.4184274641345498.png",q="/media/202507/2025-07-09_173932_9258420.9406660291469601.png",x="/media/202507/2025-07-09_174755_3148490.4047827481486951.png",D=JSON.parse('{"title":"智能体对接","description":"","frontmatter":{"title":"智能体对接"},"headers":[],"relativePath":"custom-biz/skill-studio/agent-integration.md","filePath":"custom-biz/skill-studio/agent-integration.md","lastUpdated":null}'),U={name:"custom-biz/skill-studio/agent-integration.md"};function w(y,e,E,S,B,V){return i(),a("div",null,[...e[0]||(e[0]=[o('<p>智能体介绍</p><p>智能体是一种能够自主行动、感知环境、做出决策并与环境交互的智能应用或实体。</p><p>在AIUI平台上，智能体本质上是个自定义工具，用于解决垂直场景对话任务，支持任务抽槽、信源查询、大模型调用和任务逻辑管理等能力，适用于复杂对话任务。开发时配置的对话意图是AIUI对智能体等自定义工具进行调度管理的重要依据。为智能体配置意图，可以将相关意图的用户Query分发给特定的智能体处理。</p><p><strong>- 新智能体</strong></p><p>-- 适用链路：仅支持极速交互语义链路</p><p>-- 支持能力：支持任务抽槽、信源查询、大模型调用等能力</p><p><strong>- 旧智能体</strong></p><p>-- 适用链路：仅支持通用大模型语义链路</p><p>-- 支持能力：仅支持对话意图抽取</p><h2 id="新智能体接入说明" tabindex="-1">新智能体接入说明 <a class="header-anchor" href="#新智能体接入说明" aria-label="Permalink to &quot;新智能体接入说明&quot;">​</a></h2><p>AIUI平台升级版本新智能体开发目前支持两种方式开发接入:</p><h2 id="三方智能体" tabindex="-1">三方智能体 <a class="header-anchor" href="#三方智能体" aria-label="Permalink to &quot;三方智能体&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>网址</th><th>智能体类型</th><th>请求方式</th><th>鉴权方式</th></tr></thead><tbody><tr><td><a href="#星辰平台接入">星辰Agent</a></td><td><a href="https://agent.xfyun.cn/home" target="_blank" rel="noreferrer">访问星辰Agent平台</a></td><td>智能体-工作流</td><td>HTTP</td><td>Bear Token</td></tr><tr><td><a href="#Coze平台接入">Coze</a></td><td><a href="https://www.coze.cn/home" target="_blank" rel="noreferrer">访问Coze平台</a></td><td>智能体-提示词</td><td>HTTP</td><td>个人访问令牌</td></tr><tr><td>智能体-工作流</td><td>HTTP</td><td>个人访问令牌</td><td></td><td></td></tr></tbody></table><p>1、使用高级模式后将不可在切换为模板意图编辑方案；</p><p>2、高级模式下，建议入参参数格式不要改动，因为AIUI服务内容已经做了参数结构适配，支持如交互历史等；</p><p>3、目前三方智能体仅支持单轮交互结果输出，多轮对话待将在后续服务升级中适配支持如交互历史参数透传等能力。</p><h3 id="星辰agent平台接入-工作流类" tabindex="-1">星辰Agent平台接入-工作流类 <a class="header-anchor" href="#星辰agent平台接入-工作流类" aria-label="Permalink to &quot;星辰Agent平台接入-工作流类&quot;">​</a></h3><p><strong>步骤1、创建工作流智能体：</strong> 登陆星辰Agent平台创建工作流智能体</p><p><img src="'+n+'" alt="" title="null"></p><p><strong>步骤2、智能体选择API发布：</strong> 编辑智能体完成测试后，发布智能体绑定到AIUI应用</p><ul><li>智能体创建编写完成后进行发布：选择API形式</li></ul><p><img src="'+p+'" alt="" title="null"></p><ul><li>绑定AIUI应用，获取token构建参数和工作流id（每次重新发布智能体时，记得点击:更新绑定）</li></ul><p><img src="'+s+'" alt="" title="null"></p>',24),t("p",{APISecret:""},[t("strong",null,"步骤3、构建个人token："),l(" 通过"),t("a",{href:"https://www.xfyun.cn/doc/spark/Agent04-API%E6%8E%A5%E5%85%A5.html#_4-1-%E6%89%A7%E8%A1%8C%E5%B7%A5%E4%BD%9C%E6%B5%81",title:"工作流API",target:"_blank",rel:"noreferrer"},"工作流API"),l("可以获知，个人token 构建方式为 ： {apikey}:")],-1),o('<p><img src="'+_+'" alt=""></p><p><strong>步骤4、参数配置：</strong> AIUI平台配置星辰Agent智能体信息</p><ul><li>配置授权token</li><li>配置智能体工作流id</li><li>创建意图</li><li>输出参数：同coze工作流中说明一致，现阶段建议无需配置</li></ul><p><img src="'+d+'" alt="" title="null"></p><h3 id="coze平台接入" tabindex="-1">Coze平台接入 <a class="header-anchor" href="#coze平台接入" aria-label="Permalink to &quot;Coze平台接入&quot;">​</a></h3><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>Coze平台接入主要分为提示词类、工作流两种。提示词类主要依赖提示词触发AI的单一响应，强调即时交互和灵活性；工作流类将任务拆解为多步骤流程，自动调用不同工具或模型协同完成复杂目标。</p><h4 id="coze平台-提示词类" tabindex="-1">Coze平台-提示词类 <a class="header-anchor" href="#coze平台-提示词类" aria-label="Permalink to &quot;Coze平台-提示词类&quot;">​</a></h4><p><strong>步骤1、创建提示词类智能体：</strong> 在Coze平台完成智能体创建，具体开发参考<a href="https://www.coze.cn/open/docs/guides/" target="_blank" rel="noreferrer">Coze平台文档</a></p><p><img src="'+g+'" alt="" title="null"></p><p><strong>步骤2、提示词类智能体选择API发布：</strong> Coze平台创建完成后进行智能体进行编辑测试，测试完成后发布智能体</p><p><img src="'+c+'" alt="" title="null"></p><p><strong>步骤3、Coze平台获取智能体id：</strong> 发布后可以发布页面进行 Playground 调试，在跳转页面获取智能体id（bot_id取值）</p><p><img src="'+m+'" alt="" title="null"></p><p><img src="'+u+'" alt="" title="null"></p><p><strong>步骤4、Coze平台创建个人令牌：</strong> 在【扣子API】–【授权】–【个人访问令牌】中创建令牌并记录token取值</p><p>注意：默认创建的属于临时令牌，会有有效期限制。</p><p><img src="'+h+'" alt="" title="null"></p><p><strong>步骤5、AIUI平台创建三方智能体并配置：</strong> 进入AIUI平台<a href="https://aiui.xfyun.cn/studio/agent" target="_blank" rel="noreferrer">智能体创作页面</a>，创建三方智能体（类型选择三方）</p><p><img src="'+I+'" alt=""></p><p><strong>步骤6、参数配置：</strong> 进入编辑页面，根据创建的Coze平台智能体类型进行参数选择或填写</p><ul><li>平台选择：coze</li><li>类型选择：选择智能体</li><li>key 中填入个人令牌</li><li>id 中填入智能体 bot_id</li></ul><p><img src="'+A+'" alt="" title="null"></p><p><strong>步骤7、添加AIUI意图：</strong> 创建意图是为了在AIUI全链路交互中，AIUI服务做业务转发判定，当用户请求的文本符合设置的意图时，会调用对应的智能体。</p><ul><li>创建意图：设置意图名称</li><li>添加语料：设置用户对话能进入该智能体的相关句式（大模型会进行泛化理解）</li></ul><p><img src="'+z+'" alt="" title="null"></p><h4 id="coze平台-工作流类" tabindex="-1">Coze平台-工作流类 <a class="header-anchor" href="#coze平台-工作流类" aria-label="Permalink to &quot;Coze平台-工作流类&quot;">​</a></h4><p><strong>步骤1、创建工作流类型智能体：</strong> 在Coze平台完成智能体创建，具体开发参考Coze平台文档</p><p><img src="'+f+'" alt="" title="null"></p><p><strong>步骤2、发布智能体：</strong> Coze平台创建完成后进行智能体进行编辑测试，测试完成后发布智能体</p><p><img src="'+k+'" alt="" title="null"></p><p><strong>步骤3、coze平台获取工作流id：</strong> 在编辑页面点击更多设置，跳转 Playground 调试获取工作流id（workflow_id取值）</p><p><img src="'+b+'" alt="" title="null"></p><p><img src="'+C+'" alt="" title="null"></p><p><strong>步骤4、coze平台创建个人令牌：</strong> （同创建提示词类智能体<strong>第4步</strong>） <strong>步骤5、AIUI平台创建三方智能体并配置：</strong> （同创建提示词类智能体<strong>第5步</strong>） <strong>步骤6、参数配置：</strong> 进入编辑页面，根据创建的Coze平台智能体类型进行配置</p><ul><li>平台选择：Coze</li><li>类型选择：选择工作流</li><li>key 中填入个人令牌</li><li>id 中填入智能体工作流workflow_id</li><li>请求参数key填写：注意按照示例工作流入参实际key填写</li><li>创建意图</li></ul><p><img src="'+P+'" alt="" title="null"></p><p>目前AIUI会直接把Coze平台工作流的结果整体字符串下发（不区分选择结果舒服类型：变量还是文本），如下图示例：</p><p>1、现阶段如果全链路开启了语音合成播报托管，建议智能体输出结果类型选择：返回文本；</p><p>2、输出参数控制：后续升级支持智能体返回变量类型时，提供开发者配置返回变量类型时指定参数结构抽取（目前暂未适配）</p><p><img src="'+T+'" alt="" title="null"></p><p><img src="'+q+'" alt="" title="null"></p><h2 id="模板智能体" tabindex="-1">模板智能体 <a class="header-anchor" href="#模板智能体" aria-label="Permalink to &quot;模板智能体&quot;">​</a></h2><p><strong>步骤1、创建模板智能体：</strong></p><ul><li><p>使用AIUI官方模板：进行意图配置修改</p></li><li><p>使用自定义开发：进行意图配置和修改</p></li><li><p>如果需要更高级能力进行过程控制，可以切换到高级开发模式（该能力开发平台持续优化中）</p><p>注意：智能体开发切换高级模式后，将无法在切回默认的文本意图构建界面</p></li></ul><p><strong>步骤2、发布智能体即可：</strong></p><p><img src="'+x+'" alt="" title="null"></p>',47)])])}const $=r(U,[["render",w]]);export{D as __pageData,$ as default};
